from flask import Flask, request
from pymongo import MongoClient

app = Flask(__name__)

client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
user_profiles = db['user_profiles']

@app.route('/profile', methods=['POST'])
def create_user_profile():
    request_data = request.get_json()
    user_profiles.insert_one(request_data)
    return {'result': 'user profile created'}, 201

@app.route('/profile/<id>', methods=['GET'])
def get_user_profile(id):
    user_profile = user_profiles.find_one({'_id': id})
    return user_profile

@app.route('/profile/search', methods=['GET'])
def search_user_profiles():
    query = request.args
    results = user_profiles.find(query)
    return list(results)

@app.route('/profile/aggregate', methods=['GET'])
def aggregate_user_profiles():
    pipeline = request.get_json()
    results = user_profiles.aggregate(pipeline)
    return list(results)


if __name__ == '__main__':
    app.run(debug=True)